import { useNavigate } from 'react-router-dom';
import { AlertCircle } from 'lucide-react';

export default function ReporterHome() {
  const navigate = useNavigate();
  return (
    <div className="min-h-[80vh] flex flex-col items-center justify-center p-6">
      <h1 className="text-3xl font-bold mb-10 text-gray-800">Emergency Panel</h1>
      <button 
        onClick={() => navigate('/report')}
        className="group relative flex flex-col items-center justify-center w-72 h-72 bg-red-50 border-4 border-red-600 rounded-full hover:bg-red-100 transition-all duration-300 shadow-2xl shadow-red-200"
      >
        <AlertCircle size={80} className="text-red-600 mb-4 group-active:scale-90 transition" />
        <span className="text-red-600 font-black text-xl">SOS REPORT</span>
      </button>
      <p className="mt-10 text-gray-400 italic">Finding rescuers within 5km of your location...</p>
    </div>
  );
}
